
<template>
  <div style="margin-bottom: 76px" class="detail">
    <van-form @submit="onSubmit">
      <van-divider content-position="left">基本信息</van-divider>
      <van-field
        v-model="form.isbn"
        name="isbn"
        label="图书条形码"
        placeholder="条形码"
        :rules="[{ required: true, message: '图书条形码' }]"
      />
      <van-field
        v-model="form.title"
        name="title"
        label="图书名称"
        placeholder="书名"
        :rules="[{ required: true, message: '请填写书名' }]"
      />
      <van-field
        v-model="form.author"
        name="author"
        label="作者"
        placeholder="作者名"
        :rules="[{ required: true, message: '请填写作者名' }]"
      />
      <van-field name="uploader" label="图片上传">
        <template #input>
          <van-uploader v-model="form.uploader" :max-count="1" />
        </template>
      </van-field>
      <van-field
        v-model="form.publisher"
        name="publisher"
        label="出版社"
        placeholder="作者名"
        :rules="[{ required: true, message: '出版社名称' }]"
      />
      <van-field
        v-model="form.price"
        name="price"
        label="价格(元)"
        placeholder="价格"
        :rules="[{ required: false, message: '图书价格' }]"
      />
      <van-field
        v-model="form.page"
        name="page"
        label="页数"
        placeholder="页数"
        :rules="[{ required: false, message: '图书页数' }]"
      />
      <van-field
        v-model="form.gist"
        name="note"
        rows="2"
        autosize
        label="简介"
        type="textarea"
        placeholder="请输入备注"
        show-word-limit
      />
      <van-divider content-position="left">待编辑信息</van-divider>
      <van-field
        readonly
        clickable
        name="date"
        :value="form.date"
        label="启用日期"
        placeholder="点击选择日期"
        @click="showCalendar = true"
      />

      <van-calendar v-model="showCalendar" @confirm="onConfirmTime" />
      <van-field
        v-model="form.liableer"
        name="liableer"
        label="图书责任人"
        placeholder="责任人"
        :rules="[{ required: false, message: '责任人' }]"
      />
      <van-field
        v-model="form.devoteer"
        name="devoteer"
        label="图书贡献人"
        placeholder="贡献人"
        :rules="[{ required: false, message: '贡献人' }]"
      />
      <van-field name="stat" label="图书状态">
        <template #input>
          <van-radio-group v-model="form.stat" direction="horizontal">
            <van-radio name="在库">在库</van-radio>
            <van-radio name="借出">借出</van-radio>
          </van-radio-group>
        </template>
      </van-field>
      <van-field
        readonly
        clickable
        name="library"
        :value="form.library"
        label="图书室"
        placeholder="点击选择城市"
        @click="showPicker = true"
      />
      <van-popup v-model="showPicker" position="bottom">
        <van-picker
          show-toolbar
          :columns="columns"
          @confirm="onConfirm"
          @cancel="showPicker = false"
        />
      </van-popup>
      <van-field name="num" label="借阅次数">
        <template #input>
          <van-stepper v-model="form.num" />
        </template>
      </van-field>

      <van-field name="label" label="标签"
        :rules="[{ required: true, message: '至少选择一个标签' }]"
      >
        <template #input>
          <van-checkbox-group
            v-model="form.label"
            direction="horizontal"
            class="check"
          >
            <van-checkbox name="文化" shape="square">文化</van-checkbox>
            <van-checkbox name="易经" shape="square">易经</van-checkbox>
            <van-checkbox name="艺术" shape="square">艺术</van-checkbox>
            <van-checkbox name="经济" shape="square">经济</van-checkbox>

            <van-checkbox name="习近平" shape="square">习近平</van-checkbox>
            <van-checkbox name="历史" shape="square">历史</van-checkbox>
            <van-checkbox name="工程" shape="square">工程</van-checkbox>
            <van-checkbox name="政治" shape="square">政治</van-checkbox>
            <van-checkbox name="计算机" shape="square">计算机</van-checkbox>
            <van-checkbox name="小说" shape="square">小说</van-checkbox>
            <van-checkbox name="基督教" shape="square">基督教</van-checkbox>
            <van-checkbox name="毛泽东" shape="square">毛泽东</van-checkbox>
            <van-checkbox name="国学" shape="square">国学</van-checkbox>
            <van-checkbox name="数学" shape="square">数学</van-checkbox>
            <van-checkbox name="煤矸石" shape="square">煤矸石</van-checkbox>
            <van-checkbox name="佛学" shape="square">佛学</van-checkbox>
            <van-checkbox name="茶道" shape="square">茶道</van-checkbox>
            <van-checkbox name="哲学" shape="square">哲学</van-checkbox>
          </van-checkbox-group>
        </template>
      </van-field>
      <van-field
        v-model="form.submitter"
        name="submitter"
        label="提交人"
        placeholder="提交人"
        :rules="[{ required: true, message: '提交人' }]"
      />
      <van-field
        v-model="form.organization"
        name="organization"
        label="提交人组织"
        placeholder="提交人组织"
        :rules="[{ required: true, message: '提交人组织' }]"
      />
      <van-field
        v-model="form.borrower"
        name="borrower"
        label="借阅人"
        placeholder="借阅人"
        :rules="[{ required: false, message: '借阅人' }]"
      />
      <van-field
        v-model="form.note"
        name="note"
        rows="2"
        autosize
        label="备注"
        type="textarea"
        placeholder="请输入备注"
        show-word-limit
      />
      <van-divider content-position="left">个人评价</van-divider>
      <van-field name="score" label="评分">
        <template #input>
          <van-rate v-model="form.score" />
        </template>
      </van-field>
      <van-field
        v-model="form.comment"
        name="comment"
        rows="2"
        autosize
        label="评论"
        type="textarea"
        maxlength="50"
        placeholder="请输入评论"
        show-word-limit
      />

      <div class="fix">
        <van-button round type="info" native-type="submit">提交</van-button>
      </div>
    </van-form>
  </div>
</template>
<script>
import { postbookinsert } from "../utils/api";
export default {
  created() {
    this.init();
    let { username, name } = this.$route.query;
    this.form.submitter = username;
    this.form.organization = name;
    this.form.devoteer = username;
    this.form.liableer = username;
    let data = JSON.parse(this.$route.query.data);
    Object.assign(this.form, data);
    // alert(data.img)

    this.form.uploader.push({ url: data.img });
  },
  data() {
    return {
      showCalendar: false,
      showPicker: false,
      columns: ["404图书室", "行署国际图书室", "其他"],
      form: {
        uploader: [],
        note: "",
        stat: "在库",
        num: 1,
        label: [],
        comment: "",
        library: "404图书室",
        devoteer: "",
        liableer: "",
        date: "",
        score: 3,
        submitter: "",
        organization: "",
        borrower: "",
      },
    };
  },
  methods: {
    onSubmit(values) {
      console.log("submit");

      postbookinsert(this.form).then(
        (res) => {
          // alert(JSON.stringify(res));
          if (res.data.msg === "成功") {
            this.$dd.device.notification.toast({
              icon: false,
              text: "入库成功！",
              duration: 3,
              delay: 0,
              onSuccess: function (res) {
                // 调用成功时回调
                console.log(res);
              },
              onFail: function (err) {
                // 调用失败时回调
                console.log(err);
              },
            });
            this.$router.push({ name: "Selectpage" });
          } else if (res.data.msg === "条形码已存在") {
            this.$dd.device.notification.toast({
              icon: false,
              text: "该书已入库！",
              duration: 3,
              delay: 0,
              onSuccess: function (res) {
                // 调用成功时回调
                console.log(res);
              },
              onFail: function (err) {
                // 调用失败时回调
                console.log(err);
              },
            });
            this.$router.push({ name: "Selectpage" });
          } else {
            this.$dd.device.notification.toast({
              icon: false,
              text: res.data.msg,
              duration: 3,
              delay: 0,
              onSuccess: function (res) {
                // 调用成功时回调
                console.log(res);
              },
              onFail: function (err) {
                // 调用失败时回调
                console.log(err);
              },
            });
          }
        },
        (err) => {
          this.$dd.device.notification.toast({
            icon: false,
            text: "网络错误",
            duration: 2,
            delay: 0,
            onSuccess: function (res) {
              // 调用成功时回调
              console.log(res);
            },
            onFail: function (err) {
              // 调用失败时回调
              console.log(err);
            },
          });
        }
      );
    },
    onConfirmTime(date) {
      this.form.date = `${date.getFullYear()}-${
        date.getMonth() + 1
      }-${date.getDate()}`;
      this.showCalendar = false;
    },

    onConfirm(value) {
      this.form.publisher = value;
      this.showPicker = false;
    },
    init() {
      var date = new Date();
      this.form.date = `${date.getFullYear()}-${
        date.getMonth() + 1 < 10 ? "0" + date.getMonth() : date.getMonth() + 1
      }-${date.getDate()}`;
    },
  },
};
</script>

<style lang="less">
.detail {
  background: white;
}
.fix {
  background: white;
  width: 100%;
  position: fixed;
  bottom: 0px;
  margin: 0px;
  box-sizing: border-box;
  padding: 16px;

  .van-button {
    width: 100%;
  }
}
.check > div {
  margin: 5px;
}
</style>