<template>
  <div class="INDEX">
    <div>
      <keep-alive include="Selectpage">
        <router-view></router-view>
      </keep-alive>
    </div>
    <van-tabbar v-model="active" @change="onChange">
      <van-tabbar-item icon="search">扫码</van-tabbar-item>
      <van-tabbar-item icon="setting-o">数据列表</van-tabbar-item>
    </van-tabbar>
  </div>
</template>
<script>
import { Notify } from "vant";
export default {
  name: "index",
  data() {
    return {
      active: 0,
    };
  },
  methods: {
    onChange(index) {
      switch (index) {
        case 0:
          this.$router.push({ name: "Selectpage" });
          break;

        case 1:
          this.$router.push({ name: "Tablepage" });

          break;
        default:
          break;
      }
    },
  },
};
</script>
