<template>
  <div>
    <van-field
      v-model="sms"
      center
      clearable
      label=""
      placeholder="请输入条形码"
    >
      <template #button>
        <van-button size="small" type="primary" @click="subimt"
          >手动查询</van-button
        >
      </template>
    </van-field>

    <div style="margin: 16px">
      <van-button round block type="info" @click="onclick">扫码查询</van-button>
    </div>
  </div>
</template>
<script>
import { getbookdetail, getCode, getbooklist } from "../utils/api";
import { CORP_ID } from "../utils/count";
export default {
  name: "Selectpage",
  activated() {
    if (this.username && this.name) {
      console.log("commit init ...");
    } else {
      this.$dd.device.notification.showPreloader({
        text: "初始化...",
        showIcon: true,
        onSuccess: function (res) {
          // 调用成功时回调
          console.log(res);
        },
        onFail: function (err) {
          // 调用失败时回调
          console.log(err);
        },
      });
      this.init();
    }
  },
  // created() {
  //   this.init();
  // },
  data() {
    return {
      sms: "",
      // sms: "",
      username: "",
      name: "",
    };
  },
  methods: {
    subimt() {
      console.log(this.sms);
      this.$dd.device.notification.showPreloader({
        text: "查询中..",
        showIcon: true,
        onSuccess: function (res) {
          // 调用成功时回调
          console.log(res);
        },
        onFail: function (err) {
          // 调用失败时回调
          console.log(err);
        },
      });
      this.getbookdetail(this.sms);
    },
    init() {
      let the = this;

      this.$dd.ready(function () {
        the.$dd.runtime.permission.requestAuthCode({
          corpId: CORP_ID, // 企业id
          onSuccess: function (info) {
            // code = info.code; // 通过该免登授权码可以获取用户身份
            // the.sms = info.code;
            // alert(JSON.stringify(info.code));
            getCode(info.code).then(
              (res1) => {
                the.$dd.device.notification.hidePreloader({
                  onSuccess: function (res) {
                    // 调用成功时回调
                    console.log(res);
                  },
                  onFail: function (err) {
                    // 调用失败时回调
                    console.log(err);
                  },
                });
                // alert(JSON.stringify(res1.data.data.username));
                the.name = res1.data.data.list[0];
                the.username = res1.data.data.userName;
              },
              (err) => {
                the.$dd.device.notification.hidePreloader({
                  onSuccess: function (res) {
                    // 调用成功时回调
                    console.log(res);
                  },
                  onFail: function (err) {
                    // 调用失败时回调
                    console.log(err);
                  },
                });
              }
            );
          },
        });
      });
    },
    // 扫一扫
    onclick() {
      let the = this;
      this.$dd.biz.util.scan({
        type: "all",
        onSuccess: function (res) {
          the.$dd.device.notification.showPreloader({
            text: "查询中..",
            showIcon: true,
            onSuccess: function (res) {
              // 调用成功时回调
              console.log(res);
            },
            onFail: function (err) {
              // 调用失败时回调
              console.log(err);
            },
          });
          // 调用成功时回调
          // alert(JSON.stringify(res));
          the.getbookdetail(res.text);
        },
        onFail: function (err) {
          // 调用失败时回调
          alert(JSON.stringify(err));
        },
      });
    },

    getbook(value) {
      // let fl = false;
      getbooklist().then((res) => {
        // console.log(res);
        alert(JSON.stringify(res));
        res.data.data.some((item) => {
          alert(item);
        });
      });
    },

    getbookdetail(value) {
      getbookdetail(value).then(
        (res) => {
          this.$dd.device.notification.hidePreloader({
            onSuccess: function (res) {
              // 调用成功时回调
              console.log(res);
            },
            onFail: function (err) {
              // 调用失败时回调
              console.log(err);
            },
          });
          if (res.data.showapi_res_body.remark === "success") {
            this.go(res.data.showapi_res_body.data);
          } else {
            this.$dd.device.notification.toast({
              icon: false,
              text: res.data.showapi_res_body.remark,
              duration: 3,
              delay: 0,
              onSuccess: function (res) {
                // 调用成功时回调
                console.log(res);
              },
              onFail: function (err) {
                // 调用失败时回调
                console.log(err);
              },
            });
          }
        },
        (err) => {
          this.$dd.device.notification.toast({
            icon: false,
            text: "网络错误",
            duration: 2,
            delay: 0,
            onSuccess: function (res) {
              // 调用成功时回调
              console.log(res);
            },
            onFail: function (err) {
              // 调用失败时回调
              console.log(err);
            },
          });
        }
      );
    },

    go(data) {
      this.$router.push({
        name: "detail",
        query: {
          data: JSON.stringify(data),
          name: this.name,
          username: this.username,
        },
      });
    },
  },
};
</script>