import req from './request'
import http from './http'

export function getbookdetail(isbn) {
  return http.get(`/1626-1?isbn=${isbn}&showapi_appid=740854&showapi_sign=5005fe06612c4e419d73a1e3e6d0c3f1`)
}
// https://route.showapi.com/1626-1?isbn=9787208061644&showapi_appid=740854&showapi_sign=5005fe06612c4e419d73a1e3e6d0c3f1
export function getCode(code) {
  return req.get('/tushu/book/noRegistration', {
    code
  })
}

export function getbooklist() {
  return req.get('/tushu/book/list')
}
export function postbookinsert(options) {
  return req.post('/tushu/book/insert', {
    edition: options.edition,
    pubdate: options.pubdate,
    paper: options.paper,
    img: options.img,
    gist: options.gist,
    format: options.format,
    publisher: options.publisher,
    author: options.author,
    title: options.title,
    price: options.price,
    page: options.page.toString(),
    isbn: options.isbn.toString(),
    binding: options.binding,
    produce: options.produce,
    library: options.library,
    liableer: options.liableer,
    devoteer: options.devoteer,
    note: options.note,
    stat: options.stat,
    num: options.num.toString(),
    comment: options.comment,
    label: options.label.join(','),
    date: options.date,
    // ==========
    score: options.score.toString(),
    submitter: options.submitter,
    organization: options.organization,
    borrower: options.borrower,
    strengthTitle: options.submitter + '发起的图书资料明细'
  })
}
export function getexportlist() {
  return req.get('http://121.89.242.0:48888/tushu/book/export')
}